import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / f'mkt-{source}' / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / f'mkt-{source}' / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JOSHUA = {
    "1": {
        "1": "<p><strong>Leadership transition in the ancient Near East</strong>: The death of Moses and YHWH's immediate commissioning of Joshua reflects the critical importance of leadership succession in ancient Near Eastern political thought. In Mesopotamian royal tradition, the death of a great king without immediate divine legitimation of his successor created a dangerous interregnum — chaos and enemy attack were expected during the gap. The formula 'Moses my servant is dead; now therefore arise' (v.2) compresses succession and divine authorization into a single moment, denying any gap in YHWH's direction of Israel. The Egyptian transition formula for military command ran similarly: the new commander received direct divine commission before crossing any border.</p>",
        "2": "<p><strong>The Jordan River as political boundary</strong>: The Jordan (Hebrew <em>ha-Yarden</em>) formed the natural eastern boundary of Cisjordan — the settled land of Canaan. In the Late Bronze Age (c. 1550-1200 BCE), the Jordan Valley was sparsely settled compared to the highlands, serving as a corridor rather than a population zone. The command to cross 'you and all this people' reflects the mass movement of an entire population group, not a military raid — a phenomenon well-attested in ANE texts describing the settlement of peoples in new territories (the Aramean migrations, the Sea Peoples' movements). The act of crossing a major river formally marked entry into a new political and religious sphere.</p>",
        "3": "<p><strong>\"Every place the sole of your foot will tread\"</strong>: This land-grant formula has precise parallels in ancient Near Eastern royal land grants. Hittite vassal treaties and Mesopotamian kudurru (boundary stone) documents record similar language: the king grants land to a loyal servant 'wherever your feet go.' The walking of boundaries was a formal legal act in both Mesopotamian and Anatolian practice — physically treading a territory's boundaries constituted legal possession. YHWH's promise employs this treaty-grant language: the land is Israel's by divine deed, actualized by the march through it.</p>",
        "4": "<p><strong>The territorial promise: from the wilderness to Lebanon</strong>: The geographic boundaries in v.4 — the wilderness (Negeb/Sinai desert), Lebanon (northern highlands), the Euphrates (northeast), and the Great Sea (Mediterranean) — define the maximal extent of Israelite territorial aspiration. These boundaries correspond to the traditional extent of Canaanite/Syro-Palestinian territory as understood in the Late Bronze Age. Egyptian imperial administration of Canaan used similar descriptions to define their northern Palestinian province. The Euphrates boundary was realized only briefly under David and Solomon (1 Kgs 4:21,24), confirming the aspirational nature of these borders; the full promise awaited the right king.</p>",
        "5": "<p><strong>\"No man shall stand before you\"</strong>: The formula 'no man shall stand before you all the days of your life' echoes the language of royal divine promise found in Egyptian and Mesopotamian royal inscriptions. Egyptian pharaohs received from Amun the promise that all nations would fall before them; Assyrian kings cited Assur's guarantee that no enemy could resist. YHWH's promise to Joshua democratizes this royal language — it is given not to a hereditary king but to a designated leader-servant. The phrase 'as I was with Moses, so I will be with you' makes the dynastic comparison explicit: Joshua's authority is derived from the same divine presence that authorized Moses.</p>",
        "6": "<p><strong>The commissioning formula: chazaq ve'ematz</strong>: The phrase 'be strong and courageous' (Hebrew <em>chazaq ve'ematz</em>, H2388+H553) is a standard Near Eastern commissioning formula for military commanders assuming new command. The Assyrian Annals use similar language when recounting royal speeches to generals before campaigns. The repetition of the formula three times in Joshua 1 (vv.6, 7, 9) reflects its liturgical character — it is not mere encouragement but a formal installation rite. Deuteronomy 31 records Moses speaking this same formula to Joshua before the whole assembly, ritually transferring command. In ancient military culture, such spoken commission before witnesses had legal as well as psychological force.</p>",
        "7": "<p><strong>Torah as military manual</strong>: The linkage of military success to careful observance of 'the Torah which Moses my servant commanded you' (v.7) is distinctive and counter-intuitive from a purely military standpoint. ANE military manuals (Egyptian Instructions, Assyrian tactical texts) focused on formation, logistics, and strategy. The Deuteronomistic tradition insists that Israel's military outcomes depend not on tactics but on covenant faithfulness — a theological claim that runs through the book: Achan's sin at Jericho causes defeat at Ai; circumcision precedes Jericho's fall. The juxtaposition of 'this Torah' and 'you will have good success' (v.8) is the book's programmatic statement.</p>",
        "8": "<p><strong>Meditating on the Torah: ancient literacy culture</strong>: The command to meditate on the sefer hatorah 'day and night' (v.8) and not let it depart from your mouth presupposes a culture of oral recitation and memorization rather than silent reading. In the ancient world, texts were read aloud — the word <em>hagah</em> (to meditate, H1897) means literally to murmur or mutter, the sound made during oral recitation. Literacy in the Late Bronze Age was largely the domain of professional scribes; reading was a social, voiced act. The scroll itself was a precious object — a copy of the Mosaic law (Deut 17:18-19 requires the king to write his own copy) was a mark of royal seriousness. Joshua's mandate to meditate continuously reflects the ideal of a leader steeped in the covenant text.</p>",
        "9": "<p><strong>\"Do not be dismayed\"</strong>: The Hebrew <em>al-te'aretz</em> (do not be terrified, H6206) refers specifically to the terror that strikes soldiers before battle — the psychological experience of dread that ancient armies deliberately cultivated in their enemies through intimidating displays, noise, and reputation. Assyrian royal inscriptions boast of making enemies 'submit at my feet' through fear. Israel's commanders faced a psychologically formidable task: leading a non-professional army against fortified Canaanite cities with chariots and professional soldiers. The divine assurance 'for YHWH your God is with you wherever you go' directly counters the terror-producing strategies of Canaanite military culture.</p>",
        "10": "<p><strong>Officers of the people: ancient military administration</strong>: The <em>shotrim</em> (officers, H7860) were a class of administrative officials responsible for logistics and communication. In Deuteronomy they appear alongside judges (Deut 16:18); here they function as the command structure for moving the entire people across the Jordan. Egyptian administrative texts and Mesopotamian military records reflect parallel hierarchical structures: large movements of people required intermediate administrators to relay orders from commanders to the mass. Joshua's first act as commander is administrative — organizing the people for the crossing — before any military planning occurs.</p>",
        "11": "<p><strong>Three days preparation period</strong>: The three-day period (v.11) before the Jordan crossing is a standard preparation interval in biblical narrative (cf. Exod 19:11,15; Num 11:19; Josh 2:22). In ANE military practice, such a period allowed for gathering provisions, religious preparation (purification), and final logistics. The specification 'prepare provisions for yourselves' indicates that the manna had already ceased or was about to cease — the people would feed themselves from gathered stores once they crossed. Three days also allowed for the scouts' reconnaissance of Jericho (ch2) to be completed before the whole army moved.</p>",
        "12": "<p><strong>The Transjordanian tribes: Reuben, Gad, and half-Manasseh</strong>: The settlement of the two-and-a-half tribes east of the Jordan (Num 32) had been negotiated with Moses on condition that their warriors cross to fight with Israel before returning to their families. This arrangement reflects the tribal solidarity expected in ancient Israelite society — the obligation to support kin in military campaigns before settling one's own affairs. The arrangement also reveals the political tension inherent in Transjordanian settlement: these tribes were geographically separated from the main Israelite community by the Jordan, a separation that would become a source of friction (Josh 22). Moses's grant of Gilead and Bashan recognized the pastoral suitability of those territories for cattle-raising tribes (Num 32:1-4).</p>",
        "13": "<p><strong>Moses's promise to the Transjordanian tribes</strong>: The reference to 'the word which Moses the servant of YHWH commanded you' (v.13) is a citation formula — Joshua appeals to a prior authoritative word rather than imposing his own command. This rhetorical move is significant in ancient succession contexts: a new leader who grounds his authority in his predecessor's commands demonstrates continuity rather than innovation. Assyrian kings similarly cited their fathers' divine mandates to legitimize their own campaigns. Joshua's consistent appeals to Moses's authority throughout the book (rather than claiming independent authority) are a mark of the book's Deuteronomistic theology: the Torah, not the leader's will, is the ultimate authority.</p>",
        "14": "<p><strong>Gibbore chayil: warriors of valor</strong>: The phrase <em>gibbore chayil</em> (warriors of valor, H1368+H2428) is a technical term for the professional fighting men — the elite troops who formed the core of an ancient Israelite army. The <em>chayil</em> warrior was distinguished from the general levy (<em>tzava</em>) by his training and equipment. David's 'thirty' and 'three' (2 Sam 23) were the inner circle of such warriors. The command that the Transjordanian warriors cross 'armed before your brothers' (v.14) means in battle formation, as the vanguard — a mark of honor that also reflected their military reputation. The women, children, and livestock stayed east of the Jordan, consistent with ancient military practice of leaving non-combatants at the base camp.</p>",
        "15": "<p><strong>Return to Transjordan as rest</strong>: The promise that the Transjordanian warriors will return 'to the land of your possession, which Moses the servant of YHWH gave you' (v.15) employs the Deuteronomistic term <em>menucha</em> (rest, H4496) — the theological rest of settled possession. The 'rest' that YHWH gives is not mere physical comfort but secure possession of allotted land without military threat — the achievement of the land-promise. The same term appears in Deuteronomy 12:9-10: 'you have not yet come to the rest and the inheritance.' The movement of Joshua is from promise to rest, enacted through the crossing and conquest — a theological arc that the book's structure embodies.</p>",
        "16": "<p><strong>The people's response: covenant renewal formula</strong>: The tribal leaders' response in v.16-18 ('All that you have commanded us we will do, and wherever you send us we will go') is a covenant-loyalty formula analogous to the vassal oath in Hittite suzerainty treaties. The Hittite vassal formula required the vassal to respond to the great king's commands with unconditional compliance: 'Whatever the Sun commands, we will do and obey.' The elders of Israel address Joshua in similar terms, transferring to him the covenant loyalty owed to Moses. The response 'just as we obeyed Moses in all things, so we will obey you' is a formal commissioning acclamation — the people, not just YHWH, install Joshua as successor.</p>",
        "17": "<p><strong>The death penalty for disobedience</strong>: 'Whoever rebels against your command and does not obey your words, in all that you command him, shall be put to death' (v.17) reflects the military law of ancient armies — insubordination in a campaign army was a capital offense. The Assyrian military codes prescribed death for soldiers who abandoned their position or disobeyed campaign orders. In Israel's covenant framework, disobedience to the divinely commissioned leader was simultaneously military insubordination and covenant breach. The severity of the penalty (death) was not merely organizational but theological: the conquest campaign was YHWH's war, and resistance to YHWH's designated commander was resistance to YHWH himself.</p>",
        "18": "<p><strong>Chazaq ve'ematz from the people to the leader</strong>: The closing phrase 'only be strong and courageous' (v.18) echoes YHWH's commissioning words from vv.6,7,9 — but here spoken by the people to their leader. This inverted echo is theologically significant: the encouragement that YHWH gave to Joshua, the people now give back to him. In ancient court protocol, the king gave commands downward; here the community addresses their leader with the same words the divine king used, completing a circuit. The people's wish for Joshua implicitly invokes YHWH's presence — they echo the divine word back, asking that what YHWH promised would be realized. The chapter closes with unity of divine commission and human acclamation.</p>",
    },
    "2": {
        "1": "<p><strong>Jericho: Bronze Age city and Late Bronze Age context</strong>: Tell es-Sultan (ancient Jericho) is one of the world's oldest inhabited sites, occupied continuously since the Mesolithic period (c. 9000 BCE). By the Late Bronze Age, Jericho was a modest fortified town controlling the spring of Elisha (Ain es-Sultan) — the most powerful fresh-water spring in the Jordan Valley. The city's strategic importance derived from its position at the Jordan ford and its water supply rather than its size. Late Bronze Age Jericho (stratum LB) was significantly smaller than its Early Bronze predecessor — Kathleen Kenyon's excavations (1952-58) found evidence of occupation but debated the dating of destruction levels. The text's account of Jericho as a walled city requiring a two-spy reconnaissance is consistent with a fortified Late Bronze Age administrative center.</p>",
        "2": "<p><strong>Rahab as innkeeper/prostitute</strong>: The Hebrew <em>zonah</em> (H2181) can mean either 'prostitute' or, in some scholarly readings, 'innkeeper' — a woman who provided lodging and food to travelers. The semantic overlap is not accidental: in the ancient Near East, roadside inns were often associated with sexual commerce. The Mesopotamian legal tradition (Code of Hammurabi §108-110) regulated tavern-women and their establishments, noting their role as informants for the state. Rahab's house 'on the wall' (v.15) places her at the urban periphery, a liminal social position consistent with either interpretation. The Talmudic tradition (b. Megillah 15a) identifies her as an innkeeper; the NT (Heb 11:31; Jas 2:25) and Josephus call her a prostitute. Whatever her precise role, her house was a plausible stopping point for travelers entering Jericho.</p>",
        "3": "<p><strong>The king of Jericho's intelligence network</strong>: The speed with which the king of Jericho receives information about the spies (v.3 — the same day they arrived) reveals a functioning urban intelligence apparatus. Late Bronze Age Canaanite city-states maintained communication networks for exactly this purpose: the Amarna Letters (14th century BCE) are full of urgent intelligence reports from Canaanite vassal kings to Pharaoh about troop movements, raiders, and political instability. A city expecting attack would have posted watchers at the gate to identify suspicious arrivals. The spies entered the city as evident strangers — their Hebrew identity in a Canaanite city would have been immediately conspicuous.</p>",
        "4": "<p><strong>Rahab's deception: ANE moral context</strong>: Rahab's lie to the king's messengers ('the men came to me, but I did not know where they were from') is the narrative's most ethically complex moment. Ancient Near Eastern wisdom literature (Egyptian Maxims of Ptahhotep, Mesopotamian wisdom texts) recognized that deception in service of the helpless or against tyranny could be morally defensible. The Hebrew midwives similarly lied to Pharaoh to protect Hebrew infants (Exod 1:19). The text does not moralize about Rahab's deception — it records it as a given fact without editorial judgment. The NT commendations of Rahab (Heb 11:31; Jas 2:25) focus on her faith and action, not the deception, suggesting the canonical tradition treats her choice as one made under extreme pressure with limited options.</p>",
        "5": "<p><strong>The gate and city management at nightfall</strong>: The detail that 'the gate was shut after the men went out' (v.5) reflects standard ANE urban security practice. City gates were closed at sunset in Canaanite cities — the gate was the primary defensive installation, and nighttime access required either a watchman's permission or illegal means. The Gezer Calendar (10th century BCE) and various Egyptian administrative texts confirm the routine closing of city gates at nightfall. Rahab's timing — directing the king's men toward the Jordan ford while the spies were hidden — exploits the gate-closing ritual: once the gate shut, the king's men could not easily re-enter to search, and the spies would escape through the wall.</p>",
        "6": "<p><strong>Flax stalks on the roof: archaeological context</strong>: The detail that Rahab 'had brought them up to the roof and hid them under the stalks of flax that she had laid out on the roof' (v.6) is consistent with Late Bronze Age Canaanite domestic practice. Archaeological excavations of LB Canaanite houses regularly find evidence of rooftop use for storage, drying crops, and sleeping in hot weather. Flax processing (for linen production) involved retting (soaking) and drying the stalks before weaving. The drying of flax on rooftops is attested in Palestinian agricultural practice from antiquity to the modern era. The stalks would have been dry and bundled — sufficient to conceal two men lying beneath them. This incidental detail carries the marks of genuine memory rather than literary invention.</p>",
        "7": "<p><strong>The Jordan ford and escape route</strong>: The 'ford of the Jordan' to which the king's men pursued the spies was likely one of the shallow crossings near Jericho — the fords near Adam (Tell Damiyeh, north of Jericho) or the crossing near Jericho itself. In the Judges period, control of Jordan fords was militarily decisive (Judg 3:28; 12:5-6 — the Shibboleth incident). The king's men took the road to the fords — the obvious escape route for spies from Israelite territory. Their pursuit thus drew Jericho's security forces away from the city in the wrong direction, an intelligence success that Rahab engineered through her knowledge of local geography.</p>",
        "8": "<p><strong>Rahab's theological declaration: the context of Canaanite religion</strong>: Rahab's speech in vv.9-13 is remarkable for its theological content — a Canaanite woman confessing that 'YHWH your God, he is God in heaven above and on earth below' (v.11) is a declaration that YHWH is the supreme deity over all other gods. In the Canaanite religious context, such a declaration amounted to apostasy from the Canaanite pantheon. Baal was the storm-and-rain deity who controlled the land's fertility; El was the high god of the Ugaritic texts; Ashtoreth was the goddess of war and sexuality. For a Canaanite to acknowledge YHWH as supreme over heaven and earth was to deny the efficacy of the entire Canaanite divine assembly. Rahab's confession is functionally a conversion narrative.</p>",
        "9": "<p><strong>The dread (eimah) of Israel in Canaan: psychological warfare</strong>: Rahab's report that 'your terror has fallen upon us, and all the inhabitants of the land melt before you' (v.9) describes the psychological climate in Late Bronze Age Canaan following the Exodus and wilderness victories. The Hebrew <em>eimah</em> (terror, H367) is a technical term for the supernatural dread that YHWH sends upon Israel's enemies (Exod 15:16; 23:27; Deut 2:25). Egyptian and Mesopotamian royal texts similarly describe the terror their campaigns spread among subject peoples. The Amarna Letters show Canaanite vassals in a state of panic over troop movements and political instability in the 14th century — the psychological fragility that Rahab describes was historically real in LB Canaan.</p>",
        "10": "<p><strong>Crossing the Red Sea and the defeat of Sihon and Og: regional reputation</strong>: Rahab specifically cites two events that the Canaanites had heard about: the drying of the Red Sea (v.10) and the defeats of Sihon and Og (v.10). These were the two most famous recent military/miraculous events attributed to Israel. The victories over Sihon of the Amorites (Num 21:21-31) and Og of Bashan (Num 21:33-35) were immediately adjacent geographically to Canaan — every Canaanite king would have received reports of these defeats. The Transjordanian kingdoms were known as formidable military powers, especially Og's kingdom of Bashan. Their annihilation by Israel would have been major intelligence for the Canaanite city-states, exactly as Rahab describes.</p>",
        "11": "<p><strong>\"Heart melted\" as ANE fear formula</strong>: 'Our hearts melted, and there was no spirit left in any man' (v.11) employs a physiological metaphor for terror found throughout ancient Near Eastern literature. The melting heart (<em>lev namas</em>) appears in Egyptian and Assyrian texts as the standard expression for psychological collapse before an overwhelming enemy. The Assyrian Annals describe conquered kings whose 'hearts melted like wax' before the Assyrian advance. The specificity of Rahab's language — she is not using generic politeness but employing the recognized vocabulary of military collapse — carries historical credibility: this is how a Canaanite urbanite would describe the psychology of her city's leadership in the face of Israel's approach.</p>",
        "12": "<p><strong>Covenant with Rahab: the oath formula</strong>: 'Swear to me by YHWH' (v.12) — Rahab invokes YHWH, not the Canaanite gods, as the guarantor of the spies' oath. In ancient covenant practice, oaths were sworn by one's own deity; the fact that Rahab swears by YHWH confirms her theological declaration in v.11 — she has already transferred her allegiance to YHWH before any formal conversion. The formula 'deal kindly and faithfully' (<em>hesed ve'emet</em>, H2617+H571) is the standard Hebrew covenant-loyalty phrase, used throughout the OT to describe covenantal obligation. Rahab asks for a <em>hesed</em>-bond — the same loyal love that YHWH shows to Israel. The spies grant her what amounts to a personal suzerainty treaty.</p>",
        "13": "<p><strong>\"My father, mother, brothers, and sisters\"</strong>: The scope of Rahab's request — protection for her entire family — reflects the ancient social unit of the extended family household (<em>beit av</em>, father's house). In the ancient Near East, survival and identity were bound to the family unit; to die without family was the deepest shame. Rahab's concern for her parents and siblings reflects both personal loyalty and the assumption that collective guilt and collective salvation operated at the household level. The later narrative (Josh 6:22-23) confirms that the promise was kept: all who were in her house were brought out alive. The 'house' as the unit of covenant applies in both judgment (Achan's household, ch7) and salvation (Rahab's household).</p>",
        "14": "<p><strong>The spies' oath: conditional protection</strong>: The oath the spies swear is carefully conditional: 'our life for your life, if you do not tell this our business' (v.14) — the protection is contingent on Rahab's silence and the display of the scarlet cord. This reflects the standard form of ANE conditional agreements: the protege receives guaranteed safety in exchange for specific compliance with defined terms. The treaty language 'our life for yours' inverts the normal hostage formula — rather than holding Rahab's life hostage to ensure her compliance, the spies stake their own lives on her silence. This is a reciprocal oath, not a unilateral demand.</p>",
        "15": "<p><strong>Rahab's house on the wall: urban planning</strong>: That Rahab's house was 'on the city wall and she lived in the wall' (v.15) reflects the use of casemate walls in Late Bronze Age Canaanite fortification. Casemate walls (double parallel walls with rooms between them) were a common LB defensive construction technique — the chambers between the outer and inner walls were used for storage or as living spaces. Poor urban residents often occupied these intramuros (within-the-wall) dwellings. Archaeological parallels exist at Megiddo, Hazor, and other LB Canaanite sites. Rahab's social position (peripheral, wall-dwelling) matches her social status (prostitute/innkeeper) — both placed her at the urban margin.</p>",
        "16": "<p><strong>Three-day hiding: use of wilderness terrain</strong>: The spies' three-day hiding in the hill country before returning to Joshua (v.16) reflects the terrain of the Judean wilderness between Jericho and the Jordan — the deeply dissected marl hillside terrain called the <em>Jeshimon</em> (the desolation), full of caves and wadis. The hill country around Jericho provided excellent concealment precisely because of its broken terrain; David later used the same wilderness as a hideout from Saul (1 Sam 23-24). The three-day period allowed the king's pursuit party to return to Jericho, after which the spies could safely reach the Jordan ford.</p>",
        "17": "<p><strong>The conditions of the oath</strong>: The spies reiterate the conditions of their oath in vv.17-20: the scarlet thread must be in the window; the entire family must be inside the house; Rahab must not reveal the mission. The specificity of these conditions reflects the legal precision of ancient covenant agreements — exact compliance was required for the oath to remain binding. The parallel to a property marking or identification system is significant: in ancient cities, doorposts were marked during plague passages (Exod 12:13) and agreements with identification signs. The scarlet thread in the window is functionally a treaty marker: it identifies the household as under the spies' — and YHWH's — protection.</p>",
        "18": "<p><strong>The scarlet cord (tikvat chut hashani)</strong>: The scarlet thread (<em>tikvat chut hashani</em>, H8615+H2339+H8144) combines the word for 'hope' or 'cord' (<em>tikvah</em>) with the color of blood-red (<em>shani</em>). The scarlet color was produced from the kermes insect (<em>tola'at shani</em>), a luxury dye used for priestly garments (Exod 25:4; 28:5) and purification rites (Lev 14:4; Num 19:6). The use of a costly scarlet thread in a marginal woman's window suggests the thread had protective-ritual significance beyond its function as a marker. Patristic interpretation consistently connected the scarlet cord to the blood of Christ, anticipating Heb 9:19-22 on the blood of the covenant. The thread's double meaning — the Hebrew <em>tikvah</em> means both 'cord' and 'hope' — is likely intentional.</p>",
        "19": "<p><strong>Blood-guilt provisions: ANE legal context</strong>: 'His blood shall be on his own head' (v.19) is the standard formula for self-incurred guilt in ancient Near Eastern legal texts. The Code of Hammurabi uses similar language for those who break oath conditions. 'His blood is on us' conversely means that the obligation party accepts responsibility for the blood if they fail their promise. The blood-guilt language in the spies' oath anticipates the Passover lamb's blood on the doorposts (Exod 12) — in both cases, blood marking distinguishes the household under YHWH's protection from those subject to judgment. The specificity of 'those who are with you in the house' establishes the precise scope of the covenant's protection.</p>",
        "20": "<p><strong>Silence as covenant condition</strong>: 'But if you tell this our business, then we shall be free of your oath' (v.20) — the intelligence-operational nature of the requirement is underscored. In ancient Near Eastern contexts, silence about military intelligence was a capital matter: the Hittite Instructions for Temple Officials prescribed death for those who disclosed state secrets. Rahab had already demonstrated her loyalty by hiding the spies and misdirecting the king's men. The reiteration of the silence requirement serves as a formal covenant term: her silence is both a security measure and the primary condition of the oath.</p>",
        "21": "<p><strong>\"According to your words\"</strong>: Rahab's response 'according to your words, so be it' (v.21) is a covenant-acceptance formula — she receives the terms and binds herself to them. The immediate action of 'binding the scarlet cord in the window' is the performative act that seals the agreement: the cord in the window is not merely a signal but the material embodiment of the covenant bond. In ancient legal culture, covenants required a physical act of ratification — the exchange of sandals (Ruth 4:7), the cutting of animals (Gen 15), or the setting of a boundary stone. Rahab's tying of the scarlet cord is her covenant ratification.</p>",
        "22": "<p><strong>The three-day hide: wilderness terrain</strong>: 'They went and came to the hill country and stayed there three days' (v.22) — the hill country (Hebrew <em>har</em>) west of Jericho is the deeply eroded limestone wilderness of the Judean desert, with scores of caves and ravines providing concealment. Bedouin and fugitives have used these same caves throughout history. The tradition of David's flight through this area (1 Sam 21-26) confirms its reputation as a refuge. The three days allowed the Jerichoite search party to return before the spies moved to the Jordan crossing.</p>",
        "23": "<p><strong>Return to Joshua</strong>: The spies' return and report to Joshua follows the standard military intelligence debriefing pattern: they recounted 'all that had happened to them' (v.23). Intelligence reports in ancient armies were oral, delivered directly to the commanding general. The Amarna Letters often describe Canaanite vassal kings sending detailed verbal reports about troop movements and political events. The spies' choice to report everything — including the theologically significant detail of Rahab's declaration (v.24) — is consistent with comprehensive debriefing practice. Their summary 'YHWH has given all the land into our hands' shows the theological interpretation taking precedence over tactical analysis.</p>",
        "24": "<p><strong>\"YHWH has given all the land into our hands\"</strong>: The summary statement of the spies — 'all the inhabitants of the land melt before us' (v.24) — inverts the disaster of the twelve spies' report in Numbers 13-14. There, the spies returned with 'we are not able' and described the people as giants before whom they were grasshoppers. Here, the same language of melting and terror is used, but as a reason for confidence: the land's inhabitants are already psychologically defeated. The theological framing ('YHWH has given' — perfect tense, accomplished fact) interprets the military-psychological intelligence as divine promise being fulfilled. This inverted echo of Numbers 13-14 is likely deliberate narrative theology.</p>",
    },
    "3": {
        "1": "<p><strong>Moving camp from Shittim to the Jordan</strong>: The move from Shittim (Abel-shittim, in the plains of Moab, modern Tell el-Kefrein) to the banks of the Jordan was approximately 8-12 km — a one-day march. The Jordan's western bank near Jericho is approximately 250 meters below sea level; the crossing point from Shittim was likely near Adam (Tell ed-Damiyeh) where the river narrows, or at the ford near the Wadi Kelt south of Jericho. The plain of Shittim was Israel's last encampment in Transjordan — the site of the Baal Peor incident (Num 25) and Balaam's blessing (Num 22-24). Moving from Shittim to the Jordan marked the definitive departure from Moabite territory.</p>",
        "2": "<p><strong>Three-day preparation period</strong>: The three-day period at the Jordan bank before crossing (v.2; cf. 1:11) served multiple purposes: allowing the Ark-procession order to be established, enabling ritual purification (v.5 — 'sanctify yourselves'), and completing the reconnaissance of Jericho (ch2). In ancient military practice, the days before a river crossing were used to observe the river's level and identify the safest crossing points. Spring flooding in the Jordan (barley harvest season, April-May) would have made fording impossible — the divine miracle of the standing waters was necessary precisely because normal crossing was blocked by seasonal flood.</p>",
        "3": "<p><strong>The Ark of the Covenant in procession</strong>: The Ark (<em>aron habrit</em>) functioned as YHWH's throne and battle standard in ancient Israel. In the ANE, the presence of a deity's cult image or symbol at the head of a procession or army indicated the deity's personal participation in the event. Egyptian armies carried divine standards before the troops; Assyrian armies carried the image of Assur into battle. Israel's Ark-procession theology transformed this practice: there was no image (forbidden in the second commandment) but the Ark itself — the container of the covenant tablets, surmounted by the cherubim — served as the divine throne. Its movement through the Jordan first would have been understood as YHWH himself leading the crossing.</p>",
        "4": "<p><strong>Two thousand cubits distance from the Ark</strong>: The required 2,000-cubit (approximately 900m) gap between the people and the Ark served both practical and theological functions. Practically, it ensured all the people could see the Ark's direction across the flat Jordan plain. Theologically, it marked the dangerous holiness of the divine presence: proximity to the Ark without authorization was lethal (2 Sam 6:6-7, Uzzah's death). The 2,000-cubit distance from holy things would later become embedded in the Sabbath day's journey limitation (Acts 1:12 — 'a Sabbath day's journey') and in Num 35:5's Levitical city boundaries. The spacing ensured that the Ark's path was clearly visible but that the people did not crowd the divine presence.</p>",
        "5": "<p><strong>\"Sanctify yourselves\" before crossing</strong>: The command to sanctify (<em>kadesh</em>, H6942) the people before the crossing reflects the ritual purity requirements for encounter with the divine. Sanctification typically involved washing clothes, sexual abstinence, and abstaining from certain foods for a set period (cf. Exod 19:10-15 before Sinai theophany). The Jordan crossing was not merely a military operation but a theophanic event — YHWH was about to perform 'wonders' (<em>nifla'ot</em>, H6381), the same word used for the Exodus plagues. Approaching a miraculous divine act required the people to be in a state of ritual readiness, treating the Jordan as a sacred threshold analogous to Sinai.</p>",
        "6": "<p><strong>The Ark's role in the crossing: divine procession theology</strong>: The Levitical priests carrying the Ark across the Jordan parallels the Mesopotamian divine procession ritual (Akitu festival) in which the image of Marduk was carried ceremonially from Esagila temple to the Bit Akitu (festival house) outside Babylon. The procession symbolized the deity's active participation in a cosmic event — in Babylon, the victory over chaos; in Israel, the conquest of Canaan. The key difference is that Israel's deity had no image: the Ark's holiness derived not from containing a divine form but from containing the covenant document — the tablets of the decalogue. YHWH was present in his word, not in a sculpted image.</p>",
        "7": "<p><strong>\"I will begin to exalt you\"</strong>: YHWH's promise to Joshua — 'this day I will begin to exalt you in the eyes of all Israel' (v.7) — employs the language of royal legitimation. Egyptian pharaohs were 'exalted' through divine acts performed in their presence; the people's recognition of divine favor was the basis of the leader's authority. Joshua's authority over the post-Mosaic community required this public divine validation — a miraculous event comparable to Moses's miracles before Pharaoh and at the sea. The Jordan crossing miracle serves the dual purpose of territorial entry and leadership legitimation: Israel crosses and Joshua is established as Moses's true successor in a single event.</p>",
        "8": "<p><strong>Priests standing in the Jordan</strong>: The priests were commanded to 'stand still in the Jordan' (v.8) — to remain stationary in the riverbed while the people crossed. This was not merely practical positioning but a theological statement: the Levitical priests bearing YHWH's Ark held back the Jordan's waters by their stationary presence. The contrast with normal river crossing — where waders move quickly through the current — heightened the miraculous character of the event. The motionless priests in the standing waters formed a visual tableau of divine sovereignty over the natural order: the priests did not command the water; they simply stood in YHWH's presence, and the waters obeyed.</p>",
        "9": "<p><strong>Joshua's gathering of Israel: assembly practice</strong>: 'Come here and hear the words of YHWH your God' (v.9) — the assembly of the full community to hear divine words before a major event reflects the <em>qahal</em> (assembly) tradition in Israel. The Sinai assembly (Exod 19-24), the Covenant Renewal at Shechem (Josh 24), and the Deuteronomic assembly (Deut 31) all involve gathering the entire people to hear divine speech before a turning-point event. In ancient Israelite theology, hearing the divine word as a community created solidarity and corporate accountability — the whole people witnessed the promise and became jointly responsible for its fulfillment.</p>",
        "10": "<p><strong>The seven Canaanite nations: historical ethnography</strong>: 'The Canaanites, Hittites, Hivites, Perizzites, Girgashites, Amorites, and Jebusites' (v.10) is the standard Deuteronomistic list of Canaan's pre-Israelite populations. This list reflects the ethnic complexity of Late Bronze Age Canaan, which included Canaanite city-state populations, Neo-Hittite refugees from the collapsed Hittite empire, Hurrian populations (possibly the Hivites), and various other groups. The Amarna Letters confirm this ethnic diversity: correspondents include Canaanites, Habiru, and others. The list is theological as well as historical — 'seven nations' signals completeness, and the enumeration grounds the conquest's theological purpose (replacing corrupt Canaanite culture, Deut 7:1-6) in an ethnographic reality.</p>",
        "11": "<p><strong>\"The ark of the covenant of the Lord of all the earth\"</strong>: The title <em>adon kol ha'aretz</em> (Lord of all the earth, v.11,13) appears rarely in Scripture but at key moments of YHWH's cosmic claim over the whole land. The title claims not merely Israel's patron deity but the universal sovereign — the one whose jurisdiction encompasses the earth, including Canaanite territory. In Canaanite theology, territorial deities (<em>ba'alei</em>) had jurisdiction only within their geographic domains; Israel's claim that YHWH is 'Lord of all the earth' was a direct theological challenge to Canaanite territorial religion. The Jordan crossing miracle would demonstrate that YHWH's sovereignty over Canaan was real, not merely claimed.</p>",
        "12": "<p><strong>Twelve men, one from each tribe</strong>: The selection of twelve men (one per tribe) for the memorial stone ceremony (v.12) is a symbolic act of national solidarity: all twelve tribes participate in crossing, and all twelve contribute to the memorial. In ANE treaty practice, representative numbers from each party sealed the agreement. The twelve stones from the Jordan (ch4) would serve as a tribal monument: the whole nation crossed together, and the monument represented the whole nation. This also counteracts any tendency to fragmentation: the Transjordanian tribes might have remained behind, but twelve-tribe crossing insists on the unity of Israel before YHWH.</p>",
        "13": "<p><strong>The standing water: natural parallels and miracle</strong>: 'The waters coming down from above shall stand in one heap' (v.13) describes the damming of the Jordan upstream. In 1927 CE, an earthquake collapsed the high mud banks at Adam (Tell ed-Damiyeh) and blocked the Jordan for over 21 hours. A similar event in 1906 blocked the river for 24 hours. These natural precedents (landslide-dams at Adam) provide a physical mechanism that YHWH could deploy providentially. The miracle of timing — the waters stopped precisely as the priests' feet touched the water — is the element that transcends natural explanation. Ancient readers would have recognized both the natural mechanism (blocked river) and the supernatural control of its timing.</p>",
        "14": "<p><strong>Barley harvest timing</strong>: 'The Jordan overflows all its banks throughout the time of harvest' (v.15) — the Jordan's spring flood peak coincided with the barley harvest (Nisan/Abib, March-April). The Jordan in flood is 3-5 meters deeper than its summer level and significantly wider. The timing of the crossing during flood season maximized the miraculous character: crossing was impossible by normal means, making YHWH's intervention undeniable. The agricultural calendar marker ('harvest time') confirms an early spring date — consistent with Passover observance at Gilgal (5:10, the fourteenth of Nisan) following shortly after.</p>",
        "15": "<p><strong>Priests' feet touching the water</strong>: The moment the priests' feet touched the Jordan's edge ('the feet of the priests bearing the Ark were dipped in the brink of the water,' v.15) triggered the miracle. This conditionality — the miracle did not precede the step of faith but accompanied it — is a recurring pattern in Exodus-Joshua theology. The sea did not part before Moses raised his staff; the water of Marah was not sweet before Moses threw in the tree. YHWH's miracles require a step of obedience that precedes visible confirmation. The priests' step into flood-stage Jordan with a heavy Ark was an act of considerable physical courage — faith actualized before the waters moved.</p>",
        "16": "<p><strong>Adam: the dam site</strong>: 'The waters coming down from above stood and rose up in a heap very far away, at Adam, the city that is beside Zarethan' (v.16) — Adam is Tell ed-Damiyeh at the confluence of the Jabbok River and the Jordan, approximately 28 km north of Jericho. The soft marl banks at this location are uniquely susceptible to collapse. In both 1927 and 1906, earthquake tremors triggered landslides that blocked the Jordan at exactly this location. The precision of the geographical note — 'at Adam' — is the kind of detail that characterizes genuine historical memory. The distance ('very far away') confirms that a substantial upstream dam had formed, draining the riverbed between Adam and the Dead Sea — a 28-km stretch.</p>",
        "17": "<p><strong>\"The priests stood firm on dry ground\"</strong>: The description of the priests standing firm on dry ground (<em>yabbashah</em>, H3004) in the middle of the Jordan while all Israel crossed repeats the Exodus sea-crossing language (Exod 14:22: 'on dry ground in the midst of the sea'). The verbal echo is deliberate theological typology: Joshua's crossing is a new Exodus — the same YHWH who parted the sea at the first deliverance parted the Jordan at the entrance to the land. The priests' stationary presence in the dry riverbed throughout the crossing (until the last Israelite passed, 4:18) was an act of ceremonial witness: they bore YHWH's throne through the miracle as its human bearers.</p>",
    },
    "4": {
        "1": "<p><strong>Command to set up memorial stones</strong>: YHWH's command to take twelve stones from the Jordan riverbed (v.2-3) establishes a physical memorial of the crossing. Memorial stones (<em>avanim</em>, H68; <em>matzevot</em> when standing) were the standard ANE method of commemorating significant events: treaty conclusions, military victories, and divine encounters were marked by stone monuments. The standing stones of Gezer, the stele of Mesha, and the boundary stones of Mesopotamia all served this function. Israel's use of stones for memorial is consistent with broader ANE practice but theologically redirected: the stones do not contain divine power or bear inscriptions of royal achievement; they serve as pedagogical triggers for future generations' questions.</p>",
        "2": "<p><strong>Twelve men carrying twelve stones</strong>: The one-man-per-tribe selection for the stone-carrying (v.2, cf. 3:12) ensures that the memorial is a tribal, not merely individual, act. Each tribe's representative carried one stone on his shoulder (v.5 — 'take up each man a stone on his shoulder') — a physical act of communal labor. The memorial would not be the work of priests or leaders alone but of the whole tribal confederation. The stones came from where the priests' feet stood — the holiest ground in the crossing, the spot where YHWH's presence was most concentrated. The twelve stones taken from that ground transferred the holiness of the encounter into the permanent monument.</p>",
        "3": "<p><strong>Lodging place at Gilgal</strong>: The lodging place (Hebrew <em>malon</em>) where the stones were to be erected was Gilgal — the base camp of the conquest. Gilgal (near modern Khirbet el-Mafjer, 2 km east of Jericho) became Israel's headquarters during the early conquest phase: circumcision was performed there (5:2-9), the Passover was kept there (5:10), the Gibeonite deception was discovered there (9:6), and it served as the base for multiple campaigns. The word <em>Gilgal</em> is etymologically connected to <em>galal</em> (to roll) — the rolling away of Egypt's reproach (5:9) became the etymology. Gilgal was a sacred site before Israel arrived; it is mentioned as a boundary marker in several passages (1 Sam 7:16; 10:8).</p>",
        "4": "<p><strong>Joshua calling the twelve men</strong>: The logistical detail of Joshua calling each appointed man (v.4) grounds the narrative in the specifics of military command. A general calling individually appointed men for a specific task reflects organized command structure. The appointment of twelve specific men for the stone-carrying was not improvised but had been planned (3:12) — Joshua knew who would carry the stones before the crossing. Pre-planning the memorial monument before the miracle occurred reflects the theological confidence of preparation: YHWH had promised the crossing would succeed, so the monument's bearers were already identified.</p>",
        "5": "<p><strong>\"Pass on before the Ark of YHWH\"</strong>: The command 'pass on before the Ark of YHWH your God into the middle of the Jordan' (v.5) sent the twelve men back into the riverbed while the priests still stood there — back into the miracle itself to retrieve the memorial stones. They were to pass 'before the Ark' — approaching the divine presence's location. This act required a form of the courage the priests had shown: entering a (currently dry but miraculously held) riverbed with the Ark still standing on its floor. The stones they carried back were literally taken from beneath YHWH's throne-presence — making them the most sacred commemorative objects imaginable.</p>",
        "6": "<p><strong>\"That this may be a sign among you\"</strong>: The pedagogical purpose of the memorial stones (v.6-7) employs the standard catechetical formula of Deuteronomy: the monument exists to trigger children's questions ('What do these stones mean to you?') which give parents the opportunity to transmit the tradition orally. Deuteronomy 6:20-25 uses the same pattern for the Torah commands. The monument is not self-interpreting — it requires transmitted speech to give it meaning. This reflects an oral culture's approach to memory: objects anchor stories, and stories are transmitted through interrogation and response. The physical memorial and the verbal tradition work together; neither alone suffices.</p>",
        "7": "<p><strong>\"Memorial forever\"</strong>: 'These stones shall be to the people of Israel a memorial forever' (v.7) — the <em>zikaron le'olam</em> (memorial for ever) is a liturgical claim that transcends any particular generation. Like the Passover memorial (Exod 12:14 — 'a memorial throughout your generations'), the Jordan stones were intended not for a temporary commemoration but for a permanent sign. The irony is that the exact location of Gilgal and the memorial stones has been disputed and possibly lost — the <em>le'olam</em> was conditional on continued remembrance. The text's aspiration that these stones would speak to every future generation was realized not through the physical stones (which are gone) but through this very narrative, the textual memorial that has outlasted the physical one.</p>",
        "8": "<p><strong>Israelites did as Joshua commanded</strong>: The compliance formula 'the people of Israel did as Joshua commanded' (v.8) is a standard narrative marker in Joshua-Judges for obedience that produces blessing, contrasted with non-compliance that produces disaster. The book of Joshua's first half is structured around this pattern: obedience (ch3-6, including stone memorial) → blessing; disobedience (ch7, Achan) → defeat; renewed obedience (ch8) → victory. The memorial stones' erection is part of the obedience cycle that structures the conquest narrative.</p>",
        "9": "<p><strong>Twelve stones in the Jordan itself</strong>: In addition to the twelve stones erected at Gilgal (vv.3,8), Joshua set up twelve stones in the middle of the Jordan itself, 'where the feet of the priests who bore the Ark of the Covenant stood' (v.9) — a second, underwater monument. This submerged monument would be visible only at low water seasons, a reminder of the miracle visible from the river itself. The dual monument (riverbed + Gilgal) serves different audiences: travelers crossing the Jordan at low water would see the submerged stones; the main memorial at Gilgal served the community. The text notes 'they are there to this day' — a phrase that anchors the account to a known contemporary reality.</p>",
        "10": "<p><strong>Timing: priests in the Jordan until everything was finished</strong>: 'The priests who bore the Ark stood in the midst of the Jordan until everything was finished' (v.10) — the duration of the crossing for an entire people was significant. Modern estimates suggest the full Israelite population (if numbering hundreds of thousands) could have taken many hours to cross, even through a wide, dry riverbed. The priests stood in the Jordan throughout, maintaining the miraculous dam upstream by their presence. 'The people hurried and crossed' (v.10) adds urgency: they were aware of the precarious situation — standing waters held back only by YHWH's command could return at any moment.</p>",
        "11": "<p><strong>Ark crossing last: the rear guard</strong>: 'The Ark of YHWH and the priests crossed over before the people' (v.11) — the Ark crossed last, after all the people had passed. In military procession theology, the divine standard marching last served as a rear guard, ensuring no stragglers were lost. The same theology appears in the Exodus: the pillar of cloud moved behind Israel to stand between them and the pursuing Egyptians (Exod 14:19-20). YHWH's presence both led (front of the Ark procession in the Jordan) and protected (behind, as rear guard when the Ark finally crossed). The Ark's final crossing precipitated the return of the waters (4:18) — a dramatic confirmation that the miracle's cause was YHWH's presence with the Ark, not a natural phenomenon.</p>",
        "12": "<p><strong>Transjordanian tribes crossing armed</strong>: 'The sons of Reuben, Gad, and the half-tribe of Manasseh crossed over armed before the people of Israel' (v.12) — in battle formation as Moses had commanded (Num 32:32; Josh 1:14). The Transjordanian warriors marched as vanguard, the most exposed position in any military crossing. Their presence at the front fulfilled their obligation (Num 32:17: 'we will go armed before the people of Israel') and demonstrated that Transjordanian tribes were full partners in the conquest. The approximately 40,000 armed warriors crossing the Jordan represented a substantial fighting force — the core of the conquest army.</p>",
        "13": "<p><strong>40,000 armed for war</strong>: The 40,000 armed men (v.13) is a smaller number than the census figures in Numbers (which give Reuben, Gad, and half-Manasseh over 100,000 adult males). The 40,000 may represent the select fighting men left behind to cross (rather than the total population, which stayed east of the Jordan) — the mobile combat force rather than the full tribal roll. Alternative interpretations read the large numbers in Numbers as military units ('thousands' = <em>elef</em> = a military unit of variable size) rather than literal counts. Whatever the specific count, the 40,000 represent a genuine and significant military force, consistent with the larger narrative of conquest.</p>",
        "14": "<p><strong>Joshua exalted in all Israel's sight</strong>: 'YHWH exalted Joshua in the sight of all Israel' (v.14) — the fulfillment of 3:7's promise. The Jordan miracle established Joshua's prophetic authority in the same way that Moses's plagues established Moses's authority before Israel. In the ancient world, the leader whose God performed visible wonders was vindicated as YHWH's genuine representative. The people's response — 'they feared him as they had feared Moses all the days of his life' (v.14) — grants Joshua the same reverent authority that Moses commanded. This legitimation was necessary for the conquest to proceed: Israel needed to follow Joshua into an unprecedented and terrifying military campaign.</p>",
        "15": "<p><strong>YHWH's command to Joshua</strong>: The narrative of YHWH's ongoing speech to Joshua throughout the crossing narrative (3:7-8; 4:1-3; 4:15-16) reflects the prophetic model of leadership: Joshua acts only on received divine word. This contrasts with ancient Near Eastern military commanders who acted on their own initiative and credited their victories to divine favor after the fact. In Israel's theological framework, the leader receives the divine word first and then acts — the sequence matters. The theological claim is not merely that YHWH approved Joshua's decisions but that Joshua's decisions were YHWH's decisions communicated through prophetic channel.</p>",
        "16": "<p><strong>Command to the priests to come up from the Jordan</strong>: The command to the priests to 'come up from the Jordan' (v.16) is issued through Joshua, who received it from YHWH (v.15-16) — the chain of command runs YHWH → Joshua → priests. This command chain reflects the hierarchical structure of Israel's covenant community: the divine word comes to the leader, who transmits it to the functionaries. The priests did not receive independent divine communication for leaving the riverbed — they waited for Joshua's command, which waited on YHWH's command. This chain of authority would be violated by Achan's independent action in ch7 and by the Transjordanian tribes' altar-building in ch22, both of which triggered crises.</p>",
        "17": "<p><strong>Joshua commanded the priests</strong>: 'Joshua commanded the priests' (v.17) — the verb <em>tzavah</em> (to command) is used consistently for authoritative directive speech from leader to subordinate. Joshua commanded the priests as the supreme military-religious authority of the campaign; the priests obeyed as subordinates executing received orders. The authority structure of the conquest is clear: Joshua is not merely a military general but the covenant leader whose authority encompasses the religious functionaries (Levitical priests) as well as the military and civil dimensions of Israel's life.</p>",
        "18": "<p><strong>Waters returned as soon as priests' feet lifted</strong>: 'When the soles of the priests' feet were lifted up on dry ground, the waters of the Jordan returned to their place and overflowed all its banks as before' (v.18) — the miracle reversed at the same moment it had begun: when feet touched the water (3:15), it stopped; when feet left the water, it returned. The symmetry of the miracle (entry and exit of priests' feet as the trigger) confirms the theological logic: the miracle was YHWH's response to his servants' obedient steps, not a mechanical natural event. The immediate return of the Jordan flood waters to 'all its banks as before' confirmed the miracle was not a gradual natural dam-release but a sharp, sudden reversal.</p>",
        "19": "<p><strong>The tenth of the first month at Gilgal</strong>: 'The people came up from the Jordan on the tenth day of the first month' (v.19) — the tenth of Nisan was precisely the day on which the Passover lamb was to be selected (Exod 12:3: 'on the tenth day of this month they shall take every man a lamb'). The calendar alignment is precise and likely intentional: Israel entered the land on the day of Passover lamb-selection, four days before the Passover feast (5:10). The arrival at Gilgal on the tenth of Nisan placed Israel in position to celebrate the first Passover in the land on the fourteenth (5:10) — the conquest of Canaan begins in the liturgical framework of Exodus commemoration.</p>",
        "20": "<p><strong>The twelve stones set up at Gilgal</strong>: The erection of the twelve Jordan stones at Gilgal (v.20) was the physical act that transformed the encampment into a sanctuary of memory. Gilgal ('circle of stones') may itself be named for this stone circle, or the name may have pre-existed and given the event its meaning. Circular stone monuments were common in ancient Canaan and the surrounding world — standing stone circles at Gezer, the megaliths of the Golan Heights, and Stonehenge-type structures across the ancient world all reflect the human instinct to mark sacred spaces with enduring stone. Israel's Gilgal stone circle was not a pagan sacred site but a repurposed geography: the circle of stones that had previously served Canaanite purposes became Israel's memorial of YHWH's conquest-crossing.</p>",
        "21": "<p><strong>The pedagogical question: \"What do these stones mean?\"</strong>: The anticipation of children's questions (v.21-22) is the Deuteronomic catechetical pattern (Deut 6:20; Exod 12:26-27; 13:14). The memorial object (stones) triggers the child's inquiry; the parent responds with the narrative. In oral cultures, memory is transmitted through story, and stories are elicited by visible prompts. The stones did not contain inscriptions explaining their meaning (unlike Assyrian royal stele); their meaning was maintained through verbal transmission across generations. The entire educational theory presupposes an active tradition of telling: unless parents told the Jordan story repeatedly when their children pointed to the stones, the memorial would become meaningless.</p>",
        "22": "<p><strong>\"Israel crossed the Jordan on dry ground\"</strong>: The response formula 'you shall let your children know, Israel crossed over this Jordan on dry ground' (v.22) employs the exodus parallel: 'dry ground' (yabbashah) is the technical term used in the sea-crossing (Exod 14:22,29). The repetition of the same phrase for both events was deliberate: parents teaching their children about Gilgal were teaching them to understand the Jordan crossing as a second Exodus, and the land of Canaan as a new wilderness entry. The conquest generation was the new generation that completed the exodus journey that Egypt's generation had failed to finish.</p>",
        "23": "<p><strong>\"As YHWH your God did to the Red Sea\"</strong>: The explicit comparison to the Red Sea crossing (v.23) — 'YHWH your God dried up the waters of the Jordan before you until you had crossed over, as YHWH your God did to the Red Sea' — is the interpretive key the parents were to provide. The Jordan miracle was not merely a useful engineering event but a deliberate echo of the founding miracle of Israel's existence. The two 'dry ground' crossings bracket the wilderness period: the sea-crossing began the exodus; the Jordan-crossing completed it. The catechism teaches children to see their history as a coherent pattern of divine deliverance, not a series of disconnected events.</p>",
        "24": "<p><strong>\"That all the peoples of the earth may know\"</strong>: 'That all the peoples of the earth may know the hand of YHWH is mighty' (v.24) extends the purpose of the Jordan miracle beyond Israel to a universal witness. The 'hand of YHWH' (<em>yad YHWH</em>) is the standard expression for YHWH's powerful, visible intervention in history — the Exodus plagues, the Red Sea crossing, and now the Jordan crossing were all manifestations of the divine 'hand.' The claim that Canaanite knowledge of YHWH's power would cause them to 'fear YHWH forever' (v.24) is the missionary dimension of the conquest: YHWH's reputation established through Israel's history is the basis for all nations' encounter with him. Rahab's confession (2:11) is already this fear-of-YHWH-based-on-known-history realized in one Canaanite life.</p>",
    },
    "5": {
        "1": "<p><strong>Canaanite psychological collapse</strong>: The report that all Amorite and Canaanite kings 'melted in heart' (<em>vayimmas levavam</em>) upon hearing of the Jordan crossing repeats Rahab's description (2:11) — confirming that the psychological impact of the miracle was immediate and universal in Canaan. The ANE understanding of divine portents at river crossings is relevant: a river parting before an approaching army would have been interpreted in Canaanite thought as the most powerful divine favor imaginable — the sea and river deities submitting to the Israelite God. The Canaanite kings were not merely militarily discouraged; they were theologically overwhelmed. 'There was no longer any spirit in them' — their own divine system had no answer to YHWH's Jordan miracle.</p>",
        "2": "<p><strong>Circumcision at Gilgal: flint knives</strong>: 'Make flint knives and circumcise the sons of Israel again' (v.2) — the use of flint (<em>tzur</em>, H6697) rather than metal knives for circumcision is a deliberate archaism. Zipporah circumcised Moses's son with a flint (Exod 4:25); the priestly tradition preserved flint for circumcision even when metal knives were available. In Egyptian practice, circumcision with flint knives is attested in wall paintings from Saqqara (Old Kingdom). The Egyptian practice may have influenced Israelite ritual, or both may reflect a common archaic tradition. The use of flint preserves the pre-metallurgical sacred character of the rite — some things must be done the old way precisely to maintain their connection to the original covenant.</p>",
        "3": "<p><strong>Gibeath-haaraloth: hill of the foreskins</strong>: 'Joshua made flint knives and circumcised the sons of Israel at Gibeath-haaraloth' (v.3) — 'Hill of the Foreskins' is either a place name derived from this event or a pre-existing local toponym. Place names derived from significant events were common in Israel (Beer-sheba from the well-covenant, Peniel from the face-of-God wrestling). The mass circumcision of an entire generation — all males born in the wilderness who had not been circumcised — was a surgical undertaking of enormous scale. The recovery period (v.8 — 'they remained in their places in the camp until they were healed') placed the entire army in a vulnerable state (cf. Dinah incident, Gen 34:25) — an act of deliberate reliance on YHWH's protection during the healing period.</p>",
        "4": "<p><strong>Why the wilderness generation was not circumcised</strong>: The explanation in vv.4-7 is historically precise: all the circumcised males who came out of Egypt had died in the wilderness (the forty-year judgment, Num 14:29-35); the males born in the wilderness had never been circumcised. This means the conquest army consisted entirely of uncircumcised men — not one of the fighting men of Israel was in covenant status as they prepared to fight YHWH's holy war. The priority of covenant identity (circumcision) over military readiness (entering battle uncircumcised) reflects the theology of the conquest: the battle belongs to YHWH, and YHWH's warriors must be covenant-marked before they fight as his agents.</p>",
        "5": "<p><strong>Born in the wilderness: a liminal generation</strong>: The generation born in the wilderness between the Exodus and the Jordan crossing occupied an unusual theological and sociological position. They had not experienced Egypt (they were born free in the wilderness) but had grown up under judgment (their parents' generation was excluded from the land). They had never been circumcised — the primary identity marker of covenant membership. The mass circumcision at Gilgal was thus a generational initiation rite: this generation formally entered the covenant that their parents had already received at Sinai but that they themselves had not been marked with. Gilgal completed the covenant membership of the conquest generation.</p>",
        "6": "<p><strong>Forty years in the wilderness</strong>: The forty-year wilderness period (v.6) was a precise judicial sentence (Num 14:33-34: forty days of spying = forty years of wandering, a year per day). The generation that refused to trust YHWH at Kadesh-barnea (Num 13-14) bore the punishment of dying outside the land. The wilderness generation's death is described in stark terms: 'they did not obey the voice of YHWH; YHWH swore that he would not let them see the land which YHWH had sworn to their fathers to give us.' The land flowing with milk and honey (v.6) is described not as what Israel received but as what the disobedient generation forfeited — a warning embedded in the conquest's origin story.</p>",
        "7": "<p><strong>\"Their children, whom he raised up in their place\"</strong>: 'Their children, whom he raised up in their place, Joshua circumcised' (v.7) — the conquest generation is explicitly a replacement generation. YHWH raised up new sons to replace the faithless fathers, a pattern of generational replacement under divine sovereignty that recurs in biblical narrative (Abraham's line through Isaac rather than Ishmael, Jacob chosen over Esau). The wilderness generation died without fulfilling the promise; their children did not inherit their failure but received the promise fresh. This generational structure is the theological resolution to the Numbers 13-14 crisis: YHWH's purpose cannot be permanently thwarted by one generation's failure.</p>",
        "8": "<p><strong>Healing period: vulnerability and trust</strong>: 'They remained in their places in the camp until they were healed' (v.8) — the mass circumcision created a period of maximum military vulnerability. An uncircumcised army could not attack; a recently circumcised army could not defend. In the Dinah narrative, the men of Shechem were circumcised and were attacked on the third day 'when they were sore' (Gen 34:25) — the vulnerability was well-known. Israel's willingness to undergo this vulnerability at the threshold of Canaan, with Jericho's garrison potentially aware of their presence (the Jordan crossing could not have been secret), was an act of faith in YHWH's promise of protection. The conquest begins not with military readiness but with covenant compliance.</p>",
        "9": "<p><strong>Gilgal: rolling away Egypt's reproach</strong>: 'YHWH said to Joshua, today I have rolled away the reproach of Egypt from you' (v.9) — the name Gilgal is given its theological etymology: <em>galal</em> (to roll, H1556). The 'reproach of Egypt' was the shame of being enslaved, uncircumcised (circumcision was an Egyptian practice too, but for the priestly/royal class — common slaves were uncircumcised in Egypt's social hierarchy), and under judgment in the wilderness. At Gilgal, all three dimensions of Egypt's reproach were lifted: slavery was over (forty years past), circumcision was completed, and the wilderness judgment-period had ended. The naming of the place as Gilgal preserved this theological moment: Gilgal literally embodied the rolling-away of shame and the beginning of a new identity as possessors of the land.</p>",
        "10": "<p><strong>Passover on the fourteenth of Nisan in Canaan</strong>: 'While the people of Israel were encamped at Gilgal, they kept the Passover on the fourteenth day of the month in the evening' (v.10) — this was the first Passover celebrated in the land of Canaan. The Passover at Gilgal completes the liturgical arc begun at the first Passover in Egypt (Exod 12): the first Passover marked the beginning of the Exodus; this Passover marks its completion. Passover in the plains of Moab (if it was celebrated there, which is uncertain) would have been the last in the wilderness; the Gilgal Passover is the first in the land. The Passover lamb's blood marked the doors of the faithful in Egypt; circumcision marked the covenant people at Gilgal — both rites mark the boundary between death and life, judgment and salvation.</p>",
        "11": "<p><strong>Eating the produce of the land: transition from manna</strong>: 'On the day after the Passover, on that very day, they ate of the produce of the land, unleavened cakes and parched grain' (v.11) — the produce of Canaan was consumed for the first time on the sixteenth of Nisan, the day after the Passover offering. The unleavened cakes (<em>matzot</em>) eaten at Passover were now made from Canaanite grain rather than wilderness manna — a tangible, edible sign that the land had been entered. The transition from manna to land produce was not gradual but immediate: on the day after Passover, they ate from the land.</p>",
        "12": "<p><strong>Manna ceased: ending of wilderness provision</strong>: 'The manna ceased the day after they ate of the produce of the land' (v.12) — the cessation of manna is dated precisely: the day after they ate Canaanite produce. The manna had sustained Israel for forty years (Exod 16:35 — 'the people ate manna forty years, until they came to a habitable land'). Its cessation is not described as loss but as fulfillment: the extraordinary provision of the wilderness was appropriate to wilderness conditions; land-based provision is appropriate to settled land. The ending of manna is an act of YHWH's faithfulness — having sustained Israel supernaturally through the desert, he transitions them to natural provision in the land. No more manna was needed because the land itself was YHWH's provision.</p>",
        "13": "<p><strong>Man with drawn sword: Christophany context</strong>: 'Joshua lifted up his eyes and looked, and behold, a man was standing before him with his drawn sword in his hand' (v.13) — the figure appears immediately after the Passover, as Joshua faces the first military objective (Jericho). The drawn sword (<em>cherev</em>) identifies this as a military figure, and the question 'are you for us, or for our adversaries?' establishes that Joshua initially processed him as a human soldier of unknown allegiance. The appearance of a divine messenger in human form before a critical military engagement has ANE parallels: Assyrian kings reported divine beings appearing before them before battle to promise victory. In Israel's tradition, such appearances are theophanies (Gen 18, 32) or angel-of-YHWH encounters.</p>",
        "14": "<p><strong>\"Commander of the army of YHWH\"</strong>: 'I am the commander of the army of YHWH (<em>sar-tzva-YHWH</em>)' — the title designates the leader of the heavenly host, the divine army of angels that fights YHWH's battles. The 'army of YHWH' (<em>tzva YHWH</em>) includes both angelic warriors and the stars (Judg 5:20 — 'the stars fought against Sisera'). Joshua's prostration and 'what does my lord say to his servant?' (v.14) is the response appropriate to a superior military commander — Joshua understood himself as subordinate to this commander. The encounter reframes the entire conquest: Israel's army is not fighting Canaan's cities; YHWH's heavenly army is fighting, and Israel's army is the subordinate partner. The conquest belongs to the divine commander, not to Joshua.</p>",
        "15": "<p><strong>\"Remove your sandals\"</strong>: 'Remove your sandals from your feet, for the place where you are standing is holy' (v.15) — the command repeats exactly what was said to Moses at the burning bush (Exod 3:5). This verbal echo identifies the commander's presence with the divine presence at the burning bush: the same holy ground, the same sandal-removal command, the same encounter between a human leader and YHWH's commissioning presence before a great act of deliverance. The parallel is deliberate: Joshua's encounter with the divine commander at Gilgal (just before Jericho) mirrors Moses's encounter at Horeb (just before the Exodus). Both men receive their commissions on holy ground, by the same holy presence, for parallel acts of divine deliverance.</p>",
    },
}

def main():
    existing = load_comm('context', 'joshua')
    merge_comm(existing, JOSHUA)
    save_comm('context', 'joshua', existing)
    total = sum(len(existing.get(ch, {})) for ch in ['1','2','3','4','5'])
    print(f'ch 1-5: {total} verses in output')
    print('Joshua 1-5 context commentary written.')

if __name__ == '__main__':
    main()
